/* AI Reality Check — Main JavaScript
   Handles theme toggle, mobile nav, and basic interactions. */
(function () {
  'use strict';

  // Theme toggle
  var themeToggle = document.getElementById('themeToggle');
  if (themeToggle) {
    themeToggle.addEventListener('click', function () {
      var html = document.documentElement;
      var isDark = html.classList.contains('theme-dark');
      html.classList.remove('theme-dark', 'theme-light');
      if (isDark) {
        html.classList.add('theme-light');
        try { localStorage.setItem('arc-theme', 'light'); } catch (e) {}
      } else {
        html.classList.add('theme-dark');
        try { localStorage.setItem('arc-theme', 'dark'); } catch (e) {}
      }
    });
  }

  // Mobile nav toggle
  var mobileToggle = document.querySelector('.mobile-nav-toggle');
  var mainNav = document.getElementById('main-navigation');
  if (mobileToggle && mainNav) {
    mobileToggle.addEventListener('click', function () {
      var isOpen = mainNav.classList.toggle('is-open');
      mobileToggle.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
    });
  }
})();
